const cp = require('child_process');
const input = $input.first().json;
const scanDir = (input.params && input.params.directory) || input.directory || '__DOCUMENTS_DIR__';
const projRoot = '__PROJECT_ROOT__';

try {
  const output = cp.execSync('bash scripts/scan-projects.sh "' + scanDir + '" 2>&1', {cwd: projRoot, timeout: 60000, encoding: 'utf8'});
  const now = Math.floor(Date.now() / 1000);
  const projects = output.trim().split('\n').filter(l => l.includes('|')).map(line => {
    const [name, branch, last, age, uncommitted, hasManifest, tplVer] = line.split('|');
    const days = age && age !== '0' ? Math.floor((now - parseInt(age)) / 86400) : 999;
    const activity = days <= 1 ? 'hot' : days <= 7 ? 'warm' : days <= 30 ? 'cool' : 'cold';
    return {name, branch, last_commit: last, days_since_commit: days, uncommitted: parseInt(uncommitted) || 0, has_manifest: hasManifest === 'true', template_version: tplVer, activity};
  });
  const order = {hot:0, warm:1, cool:2, cold:3};
  projects.sort((a,b) => (order[a.activity]||4) - (order[b.activity]||4));
  return [{json: {status:'complete', scanned:scanDir, total:projects.length, agent_projects:projects.filter(p=>p.has_manifest).length, summary:{hot:projects.filter(p=>p.activity==='hot').length, warm:projects.filter(p=>p.activity==='warm').length, cool:projects.filter(p=>p.activity==='cool').length, cold:projects.filter(p=>p.activity==='cold').length}, projects, timestamp:new Date().toISOString()}}];
} catch(e) {
  return [{json: {status:'error', error:(e.stderr||'')+e.message, scanned:scanDir}}];
}
